BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Heart Structure & Circulation' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Heart Structure & Circulation', 'Chambers valves circulation pathways and heart sounds', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Heart Structure & Circulation (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Heart Structure and Circulation - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Right heart role in this cardiac anatomy scenario?', 'Which finding best supports Right heart role in this cardiac anatomy scenario?', '[{"id": "a", "text": "This pattern is more consistent with Aortic valve function."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation."}]'::jsonb, '["d"]'::jsonb, 'Correct because Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation. Differentiate right-sided flow purpose when interpreting oxygenation pathways.', 'Heart Structure and Circulation - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Left heart role?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Left heart role?', '[{"id": "a", "text": "Use left-sided failure signs to infer systemic output compromise."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "Left ventricle empties into pulmonary artery in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Left heart receives oxygenated blood from pulmonary veins and pumps it systemically via aorta. Use left-sided failure signs to infer systemic output compromise.', 'Heart Structure and Circulation - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Tricuspid valve location?', 'Which clinical judgment is most accurate regarding Tricuspid valve location?', '[{"id": "a", "text": "Tricuspid opens into aorta in this note."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Tricuspid valve lies between RA and RV and prevents backflow from RV to RA."}, {"id": "d", "text": "Tricuspid sits between LA and LV in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Tricuspid valve lies between RA and RV and prevents backflow from RV to RA. Valve-location clarity supports murmur and regurgitation interpretation.', 'Heart Structure and Circulation - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Pulmonic valve function?', 'In urgent triage, which conclusion aligns with Pulmonic valve function?', '[{"id": "a", "text": "Pulmonic valve routes blood to SVC in this note."}, {"id": "b", "text": "This pattern is more consistent with Systemic circuit."}, {"id": "c", "text": "Link right ventricular systole to pulmonary artery outflow events."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pulmonic valve opens from RV into pulmonary artery during RV contraction. Link right ventricular systole to pulmonary artery outflow events.', 'Heart Structure and Circulation - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Mitral valve location?', 'Which statement most appropriately reflects Mitral valve location?', '[{"id": "a", "text": "This pattern is more consistent with Full blood flow sequence."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Mitral (bicuspid) valve is between LA and LV and prevents LV-to-LA backflow."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["c"]'::jsonb, 'Correct because Mitral (bicuspid) valve is between LA and LV and prevents LV-to-LA backflow. Recognize mitral pathology impact on pulmonary venous pressures.', 'Heart Structure and Circulation - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Aortic valve function in this cardiac anatomy scenario?', 'Which finding best supports Aortic valve function in this cardiac anatomy scenario?', '[{"id": "a", "text": "This pattern is more consistent with Artery vs vein rule."}, {"id": "b", "text": "Aortic valve opens into pulmonary artery in this note."}, {"id": "c", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "d", "text": "Aortic outflow understanding is key to systemic perfusion interpretation."}]'::jsonb, '["d"]'::jsonb, 'Correct because Aortic valve opens from LV into aorta during LV contraction to supply systemic circulation. Aortic outflow understanding is key to systemic perfusion interpretation.', 'Heart Structure and Circulation - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Valve mnemonic?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Valve mnemonic?', '[{"id": "a", "text": "Mnemonic order starts with aortic in this note."}, {"id": "b", "text": "Valve order mnemonic is Try Pulling My Aorta: Tricuspid, Pulmonic, Mitral, Aortic."}, {"id": "c", "text": "Pulmonic is last in sequence in this note."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["b"]'::jsonb, 'Correct because Valve order mnemonic is Try Pulling My Aorta: Tricuspid, Pulmonic, Mitral, Aortic. Use mnemonic to avoid right-left sequence errors under exam pressure.', 'Heart Structure and Circulation - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Pulmonary circuit?', 'Which clinical judgment is most accurate regarding Pulmonary circuit?', '[{"id": "a", "text": "Pulmonary veins carry deoxygenated blood to RA in this note."}, {"id": "b", "text": "This pattern is more consistent with Pulmonary vein exception."}, {"id": "c", "text": "Confirm oxygenation transition occurs in lungs before LA return."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pulmonary circulation route is RV to pulmonary artery to lungs to pulmonary veins to LA. Confirm oxygenation transition occurs in lungs before LA return.', 'Heart Structure and Circulation - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Systemic circuit?', 'In urgent triage, which conclusion aligns with Systemic circuit?', '[{"id": "a", "text": "This pattern is more consistent with Heart wall layers."}, {"id": "b", "text": "Systemic circulation route is LV to aorta to body tissues then venous return via SVC/IVC to RA."}, {"id": "c", "text": "Systemic return enters LA directly in this note."}, {"id": "d", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}]'::jsonb, '["b"]'::jsonb, 'Correct because Systemic circulation route is LV to aorta to body tissues then venous return via SVC/IVC to RA. Trace systemic return correctly to localize circulation problems.', 'Heart Structure and Circulation - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Full blood flow sequence?', 'Which statement most appropriately reflects Full blood flow sequence?', '[{"id": "a", "text": "Sequential mastery supports congenital/valvular defect reasoning."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "Mitral valve comes before pulmonary veins in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Complete sequence is SVC/IVCâ†’RAâ†’Tricuspidâ†’RVâ†’Pulmonicâ†’Pulmonary arteryâ†’Lungsâ†’Pulmonary veinsâ†’LAâ†’Mitralâ†’LVâ†’Aorticâ†’Aortaâ†’Body. Sequential mastery supports congenital/valvular defect reasoning.', 'Heart Structure and Circulation - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Artery vs vein rule in this cardiac anatomy scenario?', 'Which finding best supports Artery vs vein rule in this cardiac anatomy scenario?', '[{"id": "a", "text": "Arteries carry blood away from heart and veins carry blood toward heart, with pulmonary vessels as oxygenation exceptions."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "This pattern is more consistent with LCA branches."}]'::jsonb, '["a"]'::jsonb, 'Correct because Arteries carry blood away from heart and veins carry blood toward heart, with pulmonary vessels as oxygenation exceptions. Separate directionality from oxygen-content assumptions.', 'Heart Structure and Circulation - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Pulmonary artery exception?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Pulmonary artery exception?', '[{"id": "a", "text": "This pattern is more consistent with RCA territory."}, {"id": "b", "text": "Pulmonary artery is classified as a vein in this note."}, {"id": "c", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "d", "text": "Do not equate artery classification with oxygen content."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pulmonary artery is an artery carrying deoxygenated blood from RV to lungs. Do not equate artery classification with oxygen content.', 'Heart Structure and Circulation - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Pulmonary vein exception?', 'Which clinical judgment is most accurate regarding Pulmonary vein exception?', '[{"id": "a", "text": "This pattern is more consistent with S1 sound."}, {"id": "b", "text": "Pulmonary veins empty into right atrium in this note."}, {"id": "c", "text": "Pulmonary veins are veins carrying oxygenated blood from lungs to LA."}, {"id": "d", "text": "Pulmonary veins carry deoxygenated blood to RV in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pulmonary veins are veins carrying oxygenated blood from lungs to LA. Use direction-based vessel naming during differential questions.', 'Heart Structure and Circulation - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Heart wall layers?', 'In urgent triage, which conclusion aligns with Heart wall layers?', '[{"id": "a", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "b", "text": "Endocardium is outer pericardial layer in this note."}, {"id": "c", "text": "Myocardium is non-muscular lining in this note."}, {"id": "d", "text": "Layer differentiation helps map pathology (myocarditis, endocarditis, etc.)."}]'::jsonb, '["d"]'::jsonb, 'Correct because Heart wall layers are epicardium outer, myocardium muscular middle, and endocardium inner chamber/valve lining. Layer differentiation helps map pathology (myocarditis, endocarditis, etc.).', 'Heart Structure and Circulation - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Pericardium facts?', 'Which statement most appropriately reflects Pericardium facts?', '[{"id": "a", "text": "Pericardium is a double-layer sac with lubricating fluid; excess fluid may cause cardiac tamponade."}, {"id": "b", "text": "Pericardium has no fluid in normal state in this note."}, {"id": "c", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "d", "text": "This pattern is more consistent with S3 significance."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pericardium is a double-layer sac with lubricating fluid; excess fluid may cause cardiac tamponade. Monitor effusion progression because tamponade is hemodynamically dangerous.', 'Heart Structure and Circulation - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports LCA branches in this cardiac anatomy scenario?', 'Which finding best supports LCA branches in this cardiac anatomy scenario?', '[{"id": "a", "text": "LCA branches directly into PDA only in this note."}, {"id": "b", "text": "Lead-territory ischemia mapping depends on branch supply knowledge."}, {"id": "c", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "d", "text": "LCX supplies right ventricle primarily in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Left coronary artery branches into LAD and LCX; LAD supplies anterior LV and 2/3 septum, LCX supplies lateral LV wall. Lead-territory ischemia mapping depends on branch supply knowledge.', 'Heart Structure and Circulation - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches RCA territory?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches RCA territory?', '[{"id": "a", "text": "RCA supplies only left atrium in this note."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "RCA has no major branches in this note."}, {"id": "d", "text": "RCA supplies right ventricle and posterior wall and branches into PDA in this note."}]'::jsonb, '["d"]'::jsonb, 'Correct because RCA supplies right ventricle and posterior wall and branches into PDA in this note. Inferior/posterior ischemia questions require RCA territory recall.', 'Heart Structure and Circulation - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding S1 sound?', 'Which clinical judgment is most accurate regarding S1 sound?', '[{"id": "a", "text": "S1 marks end of systole in this note."}, {"id": "b", "text": "Correctly time heart sounds with valve events and cardiac cycle."}, {"id": "c", "text": "This pattern is more consistent with NCLEX sound mnemonics."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["b"]'::jsonb, 'Correct because S1 (lub) is closure of mitral and tricuspid valves at start of systole. Correctly time heart sounds with valve events and cardiac cycle.', 'Heart Structure and Circulation - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with S2 sound?', 'In urgent triage, which conclusion aligns with S2 sound?', '[{"id": "a", "text": "This pattern is more consistent with Integrated circulation reasoning."}, {"id": "b", "text": "S2 indicates ventricular filling start only in this note."}, {"id": "c", "text": "S2 (dub) is closure of aortic and pulmonic valves, marking end of systole."}, {"id": "d", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}]'::jsonb, '["c"]'::jsonb, 'Correct because S2 (dub) is closure of aortic and pulmonic valves, marking end of systole. Pair semilunar closure timing with pressure-cycle interpretation.', 'Heart Structure and Circulation - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects S3 significance?', 'Which statement most appropriately reflects S3 significance?', '[{"id": "a", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "b", "text": "New S3 in adults should prompt volume overload/heart-failure evaluation."}, {"id": "c", "text": "This pattern is more consistent with Right heart role."}, {"id": "d", "text": "S3 is normal adult athletic finding in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because S3 is linked to rapid ventricular filling and is abnormal in adults, associated with heart failure. New S3 in adults should prompt volume overload/heart-failure evaluation.', 'Heart Structure and Circulation - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports S4 significance in this cardiac anatomy scenario?', 'Which finding best supports S4 significance in this cardiac anatomy scenario?', '[{"id": "a", "text": "S4 reflects atrial kick against a stiff ventricle and is associated with hypertension and hypertrophic cardiomyopathy."}, {"id": "b", "text": "S4 indicates acute pulmonary embolism in this note."}, {"id": "c", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "d", "text": "S4 is caused by AV valve closure in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because S4 reflects atrial kick against a stiff ventricle and is associated with hypertension and hypertrophic cardiomyopathy. S4 suggests reduced ventricular compliance.', 'Heart Structure and Circulation - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Murmur meaning?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Murmur meaning?', '[{"id": "a", "text": "Murmurs are always benign in this note."}, {"id": "b", "text": "This pattern is more consistent with Tricuspid valve location."}, {"id": "c", "text": "Murmurs indicate normal laminar flow in this note."}, {"id": "d", "text": "Characterize murmurs to evaluate structural valve disease risk."}]'::jsonb, '["d"]'::jsonb, 'Correct because Murmurs represent turbulent blood flow and may indicate valve stenosis or regurgitation. Characterize murmurs to evaluate structural valve disease risk.', 'Heart Structure and Circulation - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding NCLEX sound mnemonics?', 'Which clinical judgment is most accurate regarding NCLEX sound mnemonics?', '[{"id": "a", "text": "NCLEX note links S3 to â€śKen-tuc-kyâ€ť and heart failure, and S4 to â€śTen-nes-seeâ€ť and stiff ventricles/HTN."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "This pattern is more consistent with Pulmonic valve function."}]'::jsonb, '["a"]'::jsonb, 'Correct because NCLEX note links S3 to â€śKen-tuc-kyâ€ť and heart failure, and S4 to â€śTen-nes-seeâ€ť and stiff ventricles/HTN. Memory mnemonics can speed sound interpretation under exam pressure.', 'Heart Structure and Circulation - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Integrated circulation reasoning?', 'In urgent triage, which conclusion aligns with Integrated circulation reasoning?', '[{"id": "a", "text": "Aorta returns deoxygenated blood to RA in this note."}, {"id": "b", "text": "This pattern is more consistent with Mitral valve location."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "Use exchange location to resolve oxygenation pathway questions accurately."}]'::jsonb, '["d"]'::jsonb, 'Correct because Gas exchange occurs in lungs between pulmonary artery output and pulmonary vein return, enabling oxygenated LA inflow before systemic ejection. Use exchange location to resolve oxygenation pathway questions accurately.', 'Heart Structure and Circulation - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Right heart role?', 'Which statement most appropriately reflects Right heart role?', '[{"id": "a", "text": "This pattern is more consistent with Aortic valve function."}, {"id": "b", "text": "Right atrium receives blood from pulmonary veins in this note."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation."}]'::jsonb, '["d"]'::jsonb, 'Correct because Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation. Differentiate right-sided flow purpose when interpreting oxygenation pathways.', 'Heart Structure and Circulation - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Left heart role in this cardiac anatomy scenario?', 'Which finding best supports Left heart role in this cardiac anatomy scenario?', '[{"id": "a", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "b", "text": "Use left-sided failure signs to infer systemic output compromise."}, {"id": "c", "text": "Left atrium receives blood from SVC in this note."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["b"]'::jsonb, 'Correct because Left heart receives oxygenated blood from pulmonary veins and pumps it systemically via aorta. Use left-sided failure signs to infer systemic output compromise.', 'Heart Structure and Circulation - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Tricuspid valve location?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Tricuspid valve location?', '[{"id": "a", "text": "Tricuspid opens into aorta in this note."}, {"id": "b", "text": "This pattern is more consistent with Pulmonary circuit."}, {"id": "c", "text": "Tricuspid valve lies between RA and RV and prevents backflow from RV to RA."}, {"id": "d", "text": "Tricuspid sits between LA and LV in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Tricuspid valve lies between RA and RV and prevents backflow from RV to RA. Valve-location clarity supports murmur and regurgitation interpretation.', 'Heart Structure and Circulation - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Pulmonic valve function?', 'Which clinical judgment is most accurate regarding Pulmonic valve function?', '[{"id": "a", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "b", "text": "Pulmonic valve routes blood to SVC in this note."}, {"id": "c", "text": "This pattern is more consistent with Systemic circuit."}, {"id": "d", "text": "Link right ventricular systole to pulmonary artery outflow events."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pulmonic valve opens from RV into pulmonary artery during RV contraction. Link right ventricular systole to pulmonary artery outflow events.', 'Heart Structure and Circulation - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Mitral valve location?', 'In urgent triage, which conclusion aligns with Mitral valve location?', '[{"id": "a", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "b", "text": "This pattern is more consistent with Full blood flow sequence."}, {"id": "c", "text": "Mitral (bicuspid) valve is between LA and LV and prevents LV-to-LA backflow."}, {"id": "d", "text": "Mitral has three leaflets in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Mitral (bicuspid) valve is between LA and LV and prevents LV-to-LA backflow. Recognize mitral pathology impact on pulmonary venous pressures.', 'Heart Structure and Circulation - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Aortic valve function?', 'Which statement most appropriately reflects Aortic valve function?', '[{"id": "a", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "b", "text": "Aortic outflow understanding is key to systemic perfusion interpretation."}, {"id": "c", "text": "Aortic valve functions during atrial filling in this note."}, {"id": "d", "text": "This pattern is more consistent with Artery vs vein rule."}]'::jsonb, '["b"]'::jsonb, 'Correct because Aortic valve opens from LV into aorta during LV contraction to supply systemic circulation. Aortic outflow understanding is key to systemic perfusion interpretation.', 'Heart Structure and Circulation - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Valve mnemonic in this cardiac anatomy scenario?', 'Which finding best supports Valve mnemonic in this cardiac anatomy scenario?', '[{"id": "a", "text": "Pulmonic is last in sequence in this note."}, {"id": "b", "text": "Mnemonic order starts with aortic in this note."}, {"id": "c", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "d", "text": "Valve order mnemonic is Try Pulling My Aorta: Tricuspid, Pulmonic, Mitral, Aortic."}]'::jsonb, '["d"]'::jsonb, 'Correct because Valve order mnemonic is Try Pulling My Aorta: Tricuspid, Pulmonic, Mitral, Aortic. Use mnemonic to avoid right-left sequence errors under exam pressure.', 'Heart Structure and Circulation - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Pulmonary circuit?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Pulmonary circuit?', '[{"id": "a", "text": "Pulmonary artery carries oxygenated blood to body in this note."}, {"id": "b", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "c", "text": "Confirm oxygenation transition occurs in lungs before LA return."}, {"id": "d", "text": "This pattern is more consistent with Pulmonary vein exception."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pulmonary circulation route is RV to pulmonary artery to lungs to pulmonary veins to LA. Confirm oxygenation transition occurs in lungs before LA return.', 'Heart Structure and Circulation - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Systemic circuit?', 'Which clinical judgment is most accurate regarding Systemic circuit?', '[{"id": "a", "text": "Systemic circulation route is LV to aorta to body tissues then venous return via SVC/IVC to RA."}, {"id": "b", "text": "This pattern is more consistent with Heart wall layers."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}]'::jsonb, '["a"]'::jsonb, 'Correct because Systemic circulation route is LV to aorta to body tissues then venous return via SVC/IVC to RA. Trace systemic return correctly to localize circulation problems.', 'Heart Structure and Circulation - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Full blood flow sequence?', 'In urgent triage, which conclusion aligns with Full blood flow sequence?', '[{"id": "a", "text": "Sequential mastery supports congenital/valvular defect reasoning."}, {"id": "b", "text": "This pattern is more consistent with Pericardium facts."}, {"id": "c", "text": "Mitral valve comes before pulmonary veins in this note."}, {"id": "d", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}]'::jsonb, '["a"]'::jsonb, 'Correct because Complete sequence is SVC/IVCâ†’RAâ†’Tricuspidâ†’RVâ†’Pulmonicâ†’Pulmonary arteryâ†’Lungsâ†’Pulmonary veinsâ†’LAâ†’Mitralâ†’LVâ†’Aorticâ†’Aortaâ†’Body. Sequential mastery supports congenital/valvular defect reasoning.', 'Heart Structure and Circulation - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Artery vs vein rule?', 'Which statement most appropriately reflects Artery vs vein rule?', '[{"id": "a", "text": "Arteries carry blood away from heart and veins carry blood toward heart, with pulmonary vessels as oxygenation exceptions."}, {"id": "b", "text": "Arteries always carry oxygenated blood with no exceptions in this note."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "This pattern is more consistent with LCA branches."}]'::jsonb, '["a"]'::jsonb, 'Correct because Arteries carry blood away from heart and veins carry blood toward heart, with pulmonary vessels as oxygenation exceptions. Separate directionality from oxygen-content assumptions.', 'Heart Structure and Circulation - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Pulmonary artery exception in this cardiac anatomy scenario?', 'Which finding best supports Pulmonary artery exception in this cardiac anatomy scenario?', '[{"id": "a", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "b", "text": "Pulmonary artery carries oxygenated blood from lungs in this note."}, {"id": "c", "text": "Pulmonary artery is classified as a vein in this note."}, {"id": "d", "text": "Do not equate artery classification with oxygen content."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pulmonary artery is an artery carrying deoxygenated blood from RV to lungs. Do not equate artery classification with oxygen content.', 'Heart Structure and Circulation - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Pulmonary vein exception?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches Pulmonary vein exception?', '[{"id": "a", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "b", "text": "Pulmonary veins are veins carrying oxygenated blood from lungs to LA."}, {"id": "c", "text": "This pattern is more consistent with S1 sound."}, {"id": "d", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}]'::jsonb, '["b"]'::jsonb, 'Correct because Pulmonary veins are veins carrying oxygenated blood from lungs to LA. Use direction-based vessel naming during differential questions.', 'Heart Structure and Circulation - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Heart wall layers?', 'Which clinical judgment is most accurate regarding Heart wall layers?', '[{"id": "a", "text": "Endocardium is outer pericardial layer in this note."}, {"id": "b", "text": "Myocardium is non-muscular lining in this note."}, {"id": "c", "text": "Layer differentiation helps map pathology (myocarditis, endocarditis, etc.)."}, {"id": "d", "text": "This pattern is more consistent with S2 sound."}]'::jsonb, '["c"]'::jsonb, 'Correct because Heart wall layers are epicardium outer, myocardium muscular middle, and endocardium inner chamber/valve lining. Layer differentiation helps map pathology (myocarditis, endocarditis, etc.).', 'Heart Structure and Circulation - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Pericardium facts?', 'In urgent triage, which conclusion aligns with Pericardium facts?', '[{"id": "a", "text": "This pattern is more consistent with S3 significance."}, {"id": "b", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "c", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "d", "text": "Pericardium is a double-layer sac with lubricating fluid; excess fluid may cause cardiac tamponade."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pericardium is a double-layer sac with lubricating fluid; excess fluid may cause cardiac tamponade. Monitor effusion progression because tamponade is hemodynamically dangerous.', 'Heart Structure and Circulation - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects LCA branches?', 'Which statement most appropriately reflects LCA branches?', '[{"id": "a", "text": "LCX supplies right ventricle primarily in this note."}, {"id": "b", "text": "This pattern is more consistent with S4 significance."}, {"id": "c", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "d", "text": "Lead-territory ischemia mapping depends on branch supply knowledge."}]'::jsonb, '["d"]'::jsonb, 'Correct because Left coronary artery branches into LAD and LCX; LAD supplies anterior LV and 2/3 septum, LCX supplies lateral LV wall. Lead-territory ischemia mapping depends on branch supply knowledge.', 'Heart Structure and Circulation - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports RCA territory in this cardiac anatomy scenario?', 'Which finding best supports RCA territory in this cardiac anatomy scenario?', '[{"id": "a", "text": "RCA supplies right ventricle and posterior wall and branches into PDA in this note."}, {"id": "b", "text": "This pattern is more consistent with Murmur meaning."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "RCA supplies only left atrium in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because RCA supplies right ventricle and posterior wall and branches into PDA in this note. Inferior/posterior ischemia questions require RCA territory recall.', 'Heart Structure and Circulation - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches S1 sound?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches S1 sound?', '[{"id": "a", "text": "Correctly time heart sounds with valve events and cardiac cycle."}, {"id": "b", "text": "S1 marks end of systole in this note."}, {"id": "c", "text": "This pattern is more consistent with NCLEX sound mnemonics."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["a"]'::jsonb, 'Correct because S1 (lub) is closure of mitral and tricuspid valves at start of systole. Correctly time heart sounds with valve events and cardiac cycle.', 'Heart Structure and Circulation - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding S2 sound?', 'Which clinical judgment is most accurate regarding S2 sound?', '[{"id": "a", "text": "S2 is AV valve closure in this note."}, {"id": "b", "text": "S2 (dub) is closure of aortic and pulmonic valves, marking end of systole."}, {"id": "c", "text": "This pattern is more consistent with Integrated circulation reasoning."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["b"]'::jsonb, 'Correct because S2 (dub) is closure of aortic and pulmonic valves, marking end of systole. Pair semilunar closure timing with pressure-cycle interpretation.', 'Heart Structure and Circulation - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with S3 significance?', 'In urgent triage, which conclusion aligns with S3 significance?', '[{"id": "a", "text": "New S3 in adults should prompt volume overload/heart-failure evaluation."}, {"id": "b", "text": "S3 is normal adult athletic finding in this note."}, {"id": "c", "text": "S3 indicates valvular stenosis only in this note."}, {"id": "d", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}]'::jsonb, '["a"]'::jsonb, 'Correct because S3 is linked to rapid ventricular filling and is abnormal in adults, associated with heart failure. New S3 in adults should prompt volume overload/heart-failure evaluation.', 'Heart Structure and Circulation - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects S4 significance?', 'Which statement most appropriately reflects S4 significance?', '[{"id": "a", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "S4 indicates acute pulmonary embolism in this note."}, {"id": "d", "text": "S4 reflects atrial kick against a stiff ventricle and is associated with hypertension and hypertrophic cardiomyopathy."}]'::jsonb, '["d"]'::jsonb, 'Correct because S4 reflects atrial kick against a stiff ventricle and is associated with hypertension and hypertrophic cardiomyopathy. S4 suggests reduced ventricular compliance.', 'Heart Structure and Circulation - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Murmur meaning in this cardiac anatomy scenario?', 'Which finding best supports Murmur meaning in this cardiac anatomy scenario?', '[{"id": "a", "text": "Characterize murmurs to evaluate structural valve disease risk."}, {"id": "b", "text": "This pattern is more consistent with Tricuspid valve location."}, {"id": "c", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "d", "text": "Murmurs are always benign in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Murmurs represent turbulent blood flow and may indicate valve stenosis or regurgitation. Characterize murmurs to evaluate structural valve disease risk.', 'Heart Structure and Circulation - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews cardiovascular physiology data. Which interpretation best matches NCLEX sound mnemonics?', 'The nurse reviews cardiovascular physiology data. Which interpretation best matches NCLEX sound mnemonics?', '[{"id": "a", "text": "NCLEX note links S3 to â€śKen-tuc-kyâ€ť and heart failure, and S4 to â€śTen-nes-seeâ€ť and stiff ventricles/HTN."}, {"id": "b", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "c", "text": "S3 mnemonic is Tennessee in this note."}, {"id": "d", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}]'::jsonb, '["a"]'::jsonb, 'Correct because NCLEX note links S3 to â€śKen-tuc-kyâ€ť and heart failure, and S4 to â€śTen-nes-seeâ€ť and stiff ventricles/HTN. Memory mnemonics can speed sound interpretation under exam pressure.', 'Heart Structure and Circulation - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Integrated circulation reasoning?', 'Which clinical judgment is most accurate regarding Integrated circulation reasoning?', '[{"id": "a", "text": "Aorta returns deoxygenated blood to RA in this note."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "This pattern is more consistent with Mitral valve location."}, {"id": "d", "text": "Use exchange location to resolve oxygenation pathway questions accurately."}]'::jsonb, '["d"]'::jsonb, 'Correct because Gas exchange occurs in lungs between pulmonary artery output and pulmonary vein return, enabling oxygenated LA inflow before systemic ejection. Use exchange location to resolve oxygenation pathway questions accurately.', 'Heart Structure and Circulation - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Right heart role?', 'In urgent triage, which conclusion aligns with Right heart role?', '[{"id": "a", "text": "Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Right atrium receives blood from pulmonary veins in this note."}, {"id": "d", "text": "Direction of blood flow is optional when identifying vessel type."}]'::jsonb, '["a"]'::jsonb, 'Correct because Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation. Differentiate right-sided flow purpose when interpreting oxygenation pathways.', 'Heart Structure and Circulation - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Left heart role?', 'Which statement most appropriately reflects Left heart role?', '[{"id": "a", "text": "Direction of blood flow is optional when identifying vessel type."}, {"id": "b", "text": "Valve-sequence recall has no impact on hemodynamic interpretation."}, {"id": "c", "text": "Use left-sided failure signs to infer systemic output compromise."}, {"id": "d", "text": "Left atrium receives blood from SVC in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Left heart receives oxygenated blood from pulmonary veins and pumps it systemically via aorta. Use left-sided failure signs to infer systemic output compromise.', 'Heart Structure and Circulation - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to Right heart role. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to Right heart role. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "RV pumps to lungs."}, {"id": "b", "text": "Right heart pumps oxygenated blood to aorta in this note."}, {"id": "c", "text": "Pulmonary circuit begins from right ventricle."}, {"id": "d", "text": "Right atrium receives blood from pulmonary veins in this note."}, {"id": "e", "text": "RA receives deoxygenated blood from SVC/IVC."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation.', 'Heart Structure and Circulation - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving Left heart role, which options are appropriate? (Select all that apply)', 'For assessment involving Left heart role, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "LA receives oxygenated blood from lungs."}, {"id": "b", "text": "LV pumps blood to body via aorta."}, {"id": "c", "text": "Systemic circulation is driven by left ventricle."}, {"id": "d", "text": "Left atrium receives blood from SVC in this note."}, {"id": "e", "text": "Left ventricle empties into pulmonary artery in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Left heart receives oxygenated blood from pulmonary veins and pumps it systemically via aorta.', 'Heart Structure and Circulation - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and Tricuspid valve location. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and Tricuspid valve location. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "It has three leaflets in this note."}, {"id": "b", "text": "Tricuspid opens into aorta in this note."}, {"id": "c", "text": "Tricuspid separates right atrium and ventricle."}, {"id": "d", "text": "It prevents RV-to-RA backflow."}, {"id": "e", "text": "Tricuspid sits between LA and LV in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Tricuspid valve lies between RA and RV and prevents backflow from RV to RA.', 'Heart Structure and Circulation - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Pulmonic valve function? (Select all that apply)', 'During reassessment, which observations support Pulmonic valve function? (Select all that apply)', '[{"id": "a", "text": "Pulmonic valve is between RV and pulmonary artery."}, {"id": "b", "text": "Pulmonic valve controls flow from LV to aorta in this note."}, {"id": "c", "text": "It directs blood toward lungs."}, {"id": "d", "text": "It opens with RV contraction."}, {"id": "e", "text": "Pulmonic valve routes blood to SVC in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Pulmonic valve opens from RV into pulmonary artery during RV contraction.', 'Heart Structure and Circulation - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Mitral valve location in this note? (Select all that apply)', 'Which cues are consistent with Mitral valve location in this note? (Select all that apply)', '[{"id": "a", "text": "Mitral separates LA and LV."}, {"id": "b", "text": "Mitral has three leaflets in this note."}, {"id": "c", "text": "Mitral is right-sided semilunar valve in this note."}, {"id": "d", "text": "Mitral limits LV-to-LA regurgitation."}, {"id": "e", "text": "Mitral is bicuspid (2 leaflets)."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Mitral (bicuspid) valve is between LA and LV and prevents LV-to-LA backflow.', 'Heart Structure and Circulation - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to Aortic valve function. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to Aortic valve function. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "It opens during LV systole."}, {"id": "b", "text": "Aortic valve functions during atrial filling in this note."}, {"id": "c", "text": "Aortic valve opens into pulmonary artery in this note."}, {"id": "d", "text": "Aortic valve lies between LV and aorta."}, {"id": "e", "text": "It delivers oxygenated blood to body."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Aortic valve opens from LV into aorta during LV contraction to supply systemic circulation.', 'Heart Structure and Circulation - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving Valve mnemonic, which options are appropriate? (Select all that apply)', 'For assessment involving Valve mnemonic, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "Pulmonic follows tricuspid."}, {"id": "b", "text": "Mitral then aortic complete sequence."}, {"id": "c", "text": "Pulmonic is last in sequence in this note."}, {"id": "d", "text": "Mnemonic order starts with aortic in this note."}, {"id": "e", "text": "Tricuspid is first in mnemonic."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Valve order mnemonic is Try Pulling My Aorta: Tricuspid, Pulmonic, Mitral, Aortic.', 'Heart Structure and Circulation - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and Pulmonary circuit. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and Pulmonary circuit. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "Pulmonary veins return oxygenated blood to LA."}, {"id": "b", "text": "Pulmonary artery carries oxygenated blood to body in this note."}, {"id": "c", "text": "Pulmonary veins carry deoxygenated blood to RA in this note."}, {"id": "d", "text": "RV ejects deoxygenated blood to pulmonary artery."}, {"id": "e", "text": "Gas exchange occurs in lungs."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pulmonary circulation route is RV to pulmonary artery to lungs to pulmonary veins to LA.', 'Heart Structure and Circulation - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Systemic circuit? (Select all that apply)', 'During reassessment, which observations support Systemic circuit? (Select all that apply)', '[{"id": "a", "text": "Systemic return enters LA directly in this note."}, {"id": "b", "text": "SVC/IVC return deoxygenated blood to RA."}, {"id": "c", "text": "LV drives systemic outflow through aorta."}, {"id": "d", "text": "RV pumps systemic circulation in this note."}, {"id": "e", "text": "Tissues extract oxygen peripherally."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Systemic circulation route is LV to aorta to body tissues then venous return via SVC/IVC to RA.', 'Heart Structure and Circulation - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Full blood flow sequence in this note? (Select all that apply)', 'Which cues are consistent with Full blood flow sequence in this note? (Select all that apply)', '[{"id": "a", "text": "Aortic valve precedes aorta/body in sequence."}, {"id": "b", "text": "Sequence bypasses right ventricle in this note."}, {"id": "c", "text": "Pulmonary veins precede LA in sequence."}, {"id": "d", "text": "Sequence starts with venous return to RA."}, {"id": "e", "text": "Mitral valve comes before pulmonary veins in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Complete sequence is SVC/IVCâ†’RAâ†’Tricuspidâ†’RVâ†’Pulmonicâ†’Pulmonary arteryâ†’Lungsâ†’Pulmonary veinsâ†’LAâ†’Mitralâ†’LVâ†’Aorticâ†’Aortaâ†’Body.', 'Heart Structure and Circulation - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to Artery vs vein rule. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to Artery vs vein rule. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "Veins always carry deoxygenated blood with no exceptions in this note."}, {"id": "b", "text": "Pulmonary artery/vein are oxygenation exceptions."}, {"id": "c", "text": "Arteries always carry oxygenated blood with no exceptions in this note."}, {"id": "d", "text": "Arteries move blood away from heart."}, {"id": "e", "text": "Veins return blood to heart."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Arteries carry blood away from heart and veins carry blood toward heart, with pulmonary vessels as oxygenation exceptions.', 'Heart Structure and Circulation - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving Pulmonary artery exception, which options are appropriate? (Select all that apply)', 'For assessment involving Pulmonary artery exception, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "It travels away from heart so remains an artery."}, {"id": "b", "text": "Origin is right ventricle."}, {"id": "c", "text": "Pulmonary artery is classified as a vein in this note."}, {"id": "d", "text": "Pulmonary artery is deoxygenated in this note."}, {"id": "e", "text": "Pulmonary artery carries oxygenated blood from lungs in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Pulmonary artery is an artery carrying deoxygenated blood from RV to lungs.', 'Heart Structure and Circulation - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and Pulmonary vein exception. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and Pulmonary vein exception. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "They return blood toward heart."}, {"id": "b", "text": "They empty into left atrium."}, {"id": "c", "text": "Pulmonary veins carry deoxygenated blood to RV in this note."}, {"id": "d", "text": "Pulmonary veins empty into right atrium in this note."}, {"id": "e", "text": "Pulmonary veins carry oxygenated blood."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pulmonary veins are veins carrying oxygenated blood from lungs to LA.', 'Heart Structure and Circulation - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Heart wall layers? (Select all that apply)', 'During reassessment, which observations support Heart wall layers? (Select all that apply)', '[{"id": "a", "text": "Myocardium is pumping muscle."}, {"id": "b", "text": "Endocardium is outer pericardial layer in this note."}, {"id": "c", "text": "Myocardium is non-muscular lining in this note."}, {"id": "d", "text": "Epicardium is outer layer."}, {"id": "e", "text": "Endocardium lines chambers/valves."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Heart wall layers are epicardium outer, myocardium muscular middle, and endocardium inner chamber/valve lining.', 'Heart Structure and Circulation - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Pericardium facts in this note? (Select all that apply)', 'Which cues are consistent with Pericardium facts in this note? (Select all that apply)', '[{"id": "a", "text": "Pericardium has two layers in note."}, {"id": "b", "text": "Pericardium has no fluid in normal state in this note."}, {"id": "c", "text": "Excess pericardial fluid improves output in this note."}, {"id": "d", "text": "Lubricating fluid reduces friction."}, {"id": "e", "text": "Excess fluid can lead to tamponade."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericardium is a double-layer sac with lubricating fluid; excess fluid may cause cardiac tamponade.', 'Heart Structure and Circulation - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to LCA branches. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to LCA branches. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "LCA branches directly into PDA only in this note."}, {"id": "b", "text": "LAD supplies anterior wall and most septum."}, {"id": "c", "text": "LAD and LCX branch from LCA."}, {"id": "d", "text": "LCX supplies lateral LV wall."}, {"id": "e", "text": "LCX supplies right ventricle primarily in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Left coronary artery branches into LAD and LCX; LAD supplies anterior LV and 2/3 septum, LCX supplies lateral LV wall.', 'Heart Structure and Circulation - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving RCA territory, which options are appropriate? (Select all that apply)', 'For assessment involving RCA territory, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "PDA branch from RCA is listed."}, {"id": "b", "text": "RCA has no major branches in this note."}, {"id": "c", "text": "Posterior wall supply is associated with RCA here."}, {"id": "d", "text": "RCA supplies right ventricle."}, {"id": "e", "text": "RCA supplies only left atrium in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: RCA supplies right ventricle and posterior wall and branches into PDA in this note.', 'Heart Structure and Circulation - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and S1 sound. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and S1 sound. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "S1 corresponds to AV valve closure."}, {"id": "b", "text": "S1 is a normal sound in this context."}, {"id": "c", "text": "S1 marks end of systole in this note."}, {"id": "d", "text": "S1 is semilunar valve closure in this note."}, {"id": "e", "text": "S1 marks beginning of systole."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: S1 (lub) is closure of mitral and tricuspid valves at start of systole.', 'Heart Structure and Circulation - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support S2 sound? (Select all that apply)', 'During reassessment, which observations support S2 sound? (Select all that apply)', '[{"id": "a", "text": "S2 is AV valve closure in this note."}, {"id": "b", "text": "S2 is semilunar valve closure."}, {"id": "c", "text": "Aortic and pulmonic closure create S2."}, {"id": "d", "text": "S2 indicates ventricular filling start only in this note."}, {"id": "e", "text": "S2 marks end of systole."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: S2 (dub) is closure of aortic and pulmonic valves, marking end of systole.', 'Heart Structure and Circulation - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with S3 significance in this note? (Select all that apply)', 'Which cues are consistent with S3 significance in this note? (Select all that apply)', '[{"id": "a", "text": "S3 associates with heart failure."}, {"id": "b", "text": "S3 in adults is abnormal in this note."}, {"id": "c", "text": "S3 indicates valvular stenosis only in this note."}, {"id": "d", "text": "S3 is tied to rapid ventricular filling."}, {"id": "e", "text": "S3 is normal adult athletic finding in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: S3 is linked to rapid ventricular filling and is abnormal in adults, associated with heart failure.', 'Heart Structure and Circulation - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to S4 significance. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to S4 significance. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "S4 comes from atrial kick into stiff ventricle."}, {"id": "b", "text": "S4 is caused by AV valve closure in this note."}, {"id": "c", "text": "S4 indicates acute pulmonary embolism in this note."}, {"id": "d", "text": "Hypertension is linked with S4 in note."}, {"id": "e", "text": "HCM is linked with S4 in note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: S4 reflects atrial kick against a stiff ventricle and is associated with hypertension and hypertrophic cardiomyopathy.', 'Heart Structure and Circulation - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving Murmur meaning, which options are appropriate? (Select all that apply)', 'For assessment involving Murmur meaning, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "Stenosis can cause murmur."}, {"id": "b", "text": "Regurgitation can cause murmur."}, {"id": "c", "text": "Murmurs indicate normal laminar flow in this note."}, {"id": "d", "text": "Murmurs are always benign in this note."}, {"id": "e", "text": "Murmur means turbulent flow."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Murmurs represent turbulent blood flow and may indicate valve stenosis or regurgitation.', 'Heart Structure and Circulation - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and NCLEX sound mnemonics. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and NCLEX sound mnemonics. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "S4 mnemonic is Tennessee in note."}, {"id": "b", "text": "S4 is linked to normal youthful physiology in this note."}, {"id": "c", "text": "Mnemonic pairing reflects HF vs stiff ventricle context."}, {"id": "d", "text": "S3 mnemonic is Tennessee in this note."}, {"id": "e", "text": "S3 mnemonic is Kentucky in note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: NCLEX note links S3 to â€śKen-tuc-kyâ€ť and heart failure, and S4 to â€śTen-nes-seeâ€ť and stiff ventricles/HTN.', 'Heart Structure and Circulation - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Integrated circulation reasoning? (Select all that apply)', 'During reassessment, which observations support Integrated circulation reasoning? (Select all that apply)', '[{"id": "a", "text": "Aorta returns deoxygenated blood to RA in this note."}, {"id": "b", "text": "Lungs are gas-exchange site in sequence."}, {"id": "c", "text": "Pulmonary venous return is oxygenated."}, {"id": "d", "text": "LA receives oxygenated blood before LV systemic ejection."}, {"id": "e", "text": "Gas exchange occurs in left ventricle in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Gas exchange occurs in lungs between pulmonary artery output and pulmonary vein return, enabling oxygenated LA inflow before systemic ejection.', 'Heart Structure and Circulation - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Right heart role in this note? (Select all that apply)', 'Which cues are consistent with Right heart role in this note? (Select all that apply)', '[{"id": "a", "text": "Right atrium receives blood from pulmonary veins in this note."}, {"id": "b", "text": "Pulmonary circuit begins from right ventricle."}, {"id": "c", "text": "RA receives deoxygenated blood from SVC/IVC."}, {"id": "d", "text": "RV pumps to lungs."}, {"id": "e", "text": "Right heart pumps oxygenated blood to aorta in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation.', 'Heart Structure and Circulation - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to Left heart role. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to Left heart role. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "Left atrium receives blood from SVC in this note."}, {"id": "b", "text": "LV pumps blood to body via aorta."}, {"id": "c", "text": "LA receives oxygenated blood from lungs."}, {"id": "d", "text": "Systemic circulation is driven by left ventricle."}, {"id": "e", "text": "Left ventricle empties into pulmonary artery in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Left heart receives oxygenated blood from pulmonary veins and pumps it systemically via aorta.', 'Heart Structure and Circulation - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving Tricuspid valve location, which options are appropriate? (Select all that apply)', 'For assessment involving Tricuspid valve location, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "Tricuspid sits between LA and LV in this note."}, {"id": "b", "text": "Tricuspid separates right atrium and ventricle."}, {"id": "c", "text": "It prevents RV-to-RA backflow."}, {"id": "d", "text": "It has three leaflets in this note."}, {"id": "e", "text": "Tricuspid opens into aorta in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Tricuspid valve lies between RA and RV and prevents backflow from RV to RA.', 'Heart Structure and Circulation - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and Pulmonic valve function. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and Pulmonic valve function. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "It directs blood toward lungs."}, {"id": "b", "text": "Pulmonic valve is between RV and pulmonary artery."}, {"id": "c", "text": "Pulmonic valve controls flow from LV to aorta in this note."}, {"id": "d", "text": "It opens with RV contraction."}, {"id": "e", "text": "Pulmonic valve routes blood to SVC in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Pulmonic valve opens from RV into pulmonary artery during RV contraction.', 'Heart Structure and Circulation - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Mitral valve location? (Select all that apply)', 'During reassessment, which observations support Mitral valve location? (Select all that apply)', '[{"id": "a", "text": "Mitral is right-sided semilunar valve in this note."}, {"id": "b", "text": "Mitral has three leaflets in this note."}, {"id": "c", "text": "Mitral separates LA and LV."}, {"id": "d", "text": "Mitral limits LV-to-LA regurgitation."}, {"id": "e", "text": "Mitral is bicuspid (2 leaflets)."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Mitral (bicuspid) valve is between LA and LV and prevents LV-to-LA backflow.', 'Heart Structure and Circulation - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Aortic valve function in this note? (Select all that apply)', 'Which cues are consistent with Aortic valve function in this note? (Select all that apply)', '[{"id": "a", "text": "Aortic valve opens into pulmonary artery in this note."}, {"id": "b", "text": "Aortic valve functions during atrial filling in this note."}, {"id": "c", "text": "It opens during LV systole."}, {"id": "d", "text": "It delivers oxygenated blood to body."}, {"id": "e", "text": "Aortic valve lies between LV and aorta."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Aortic valve opens from LV into aorta during LV contraction to supply systemic circulation.', 'Heart Structure and Circulation - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to Valve mnemonic. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to Valve mnemonic. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "Mitral then aortic complete sequence."}, {"id": "b", "text": "Pulmonic is last in sequence in this note."}, {"id": "c", "text": "Tricuspid is first in mnemonic."}, {"id": "d", "text": "Pulmonic follows tricuspid."}, {"id": "e", "text": "Mnemonic order starts with aortic in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Valve order mnemonic is Try Pulling My Aorta: Tricuspid, Pulmonic, Mitral, Aortic.', 'Heart Structure and Circulation - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving Pulmonary circuit, which options are appropriate? (Select all that apply)', 'For assessment involving Pulmonary circuit, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "Pulmonary veins return oxygenated blood to LA."}, {"id": "b", "text": "Pulmonary artery carries oxygenated blood to body in this note."}, {"id": "c", "text": "RV ejects deoxygenated blood to pulmonary artery."}, {"id": "d", "text": "Pulmonary veins carry deoxygenated blood to RA in this note."}, {"id": "e", "text": "Gas exchange occurs in lungs."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pulmonary circulation route is RV to pulmonary artery to lungs to pulmonary veins to LA.', 'Heart Structure and Circulation - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and Systemic circuit. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and Systemic circuit. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "Tissues extract oxygen peripherally."}, {"id": "b", "text": "Systemic return enters LA directly in this note."}, {"id": "c", "text": "LV drives systemic outflow through aorta."}, {"id": "d", "text": "SVC/IVC return deoxygenated blood to RA."}, {"id": "e", "text": "RV pumps systemic circulation in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Systemic circulation route is LV to aorta to body tissues then venous return via SVC/IVC to RA.', 'Heart Structure and Circulation - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Full blood flow sequence? (Select all that apply)', 'During reassessment, which observations support Full blood flow sequence? (Select all that apply)', '[{"id": "a", "text": "Sequence starts with venous return to RA."}, {"id": "b", "text": "Sequence bypasses right ventricle in this note."}, {"id": "c", "text": "Pulmonary veins precede LA in sequence."}, {"id": "d", "text": "Aortic valve precedes aorta/body in sequence."}, {"id": "e", "text": "Mitral valve comes before pulmonary veins in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Complete sequence is SVC/IVCâ†’RAâ†’Tricuspidâ†’RVâ†’Pulmonicâ†’Pulmonary arteryâ†’Lungsâ†’Pulmonary veinsâ†’LAâ†’Mitralâ†’LVâ†’Aorticâ†’Aortaâ†’Body.', 'Heart Structure and Circulation - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Artery vs vein rule in this note? (Select all that apply)', 'Which cues are consistent with Artery vs vein rule in this note? (Select all that apply)', '[{"id": "a", "text": "Arteries always carry oxygenated blood with no exceptions in this note."}, {"id": "b", "text": "Veins always carry deoxygenated blood with no exceptions in this note."}, {"id": "c", "text": "Veins return blood to heart."}, {"id": "d", "text": "Pulmonary artery/vein are oxygenation exceptions."}, {"id": "e", "text": "Arteries move blood away from heart."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Arteries carry blood away from heart and veins carry blood toward heart, with pulmonary vessels as oxygenation exceptions.', 'Heart Structure and Circulation - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to Pulmonary artery exception. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to Pulmonary artery exception. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pulmonary artery is deoxygenated in this note."}, {"id": "b", "text": "It travels away from heart so remains an artery."}, {"id": "c", "text": "Origin is right ventricle."}, {"id": "d", "text": "Pulmonary artery carries oxygenated blood from lungs in this note."}, {"id": "e", "text": "Pulmonary artery is classified as a vein in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Pulmonary artery is an artery carrying deoxygenated blood from RV to lungs.', 'Heart Structure and Circulation - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving Pulmonary vein exception, which options are appropriate? (Select all that apply)', 'For assessment involving Pulmonary vein exception, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "They return blood toward heart."}, {"id": "b", "text": "Pulmonary veins carry deoxygenated blood to RV in this note."}, {"id": "c", "text": "Pulmonary veins empty into right atrium in this note."}, {"id": "d", "text": "Pulmonary veins carry oxygenated blood."}, {"id": "e", "text": "They empty into left atrium."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pulmonary veins are veins carrying oxygenated blood from lungs to LA.', 'Heart Structure and Circulation - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and Heart wall layers. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and Heart wall layers. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "Myocardium is pumping muscle."}, {"id": "b", "text": "Endocardium is outer pericardial layer in this note."}, {"id": "c", "text": "Myocardium is non-muscular lining in this note."}, {"id": "d", "text": "Epicardium is outer layer."}, {"id": "e", "text": "Endocardium lines chambers/valves."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Heart wall layers are epicardium outer, myocardium muscular middle, and endocardium inner chamber/valve lining.', 'Heart Structure and Circulation - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Pericardium facts? (Select all that apply)', 'During reassessment, which observations support Pericardium facts? (Select all that apply)', '[{"id": "a", "text": "Excess fluid can lead to tamponade."}, {"id": "b", "text": "Pericardium has two layers in note."}, {"id": "c", "text": "Excess pericardial fluid improves output in this note."}, {"id": "d", "text": "Pericardium has no fluid in normal state in this note."}, {"id": "e", "text": "Lubricating fluid reduces friction."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericardium is a double-layer sac with lubricating fluid; excess fluid may cause cardiac tamponade.', 'Heart Structure and Circulation - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with LCA branches in this note? (Select all that apply)', 'Which cues are consistent with LCA branches in this note? (Select all that apply)', '[{"id": "a", "text": "LCX supplies lateral LV wall."}, {"id": "b", "text": "LCA branches directly into PDA only in this note."}, {"id": "c", "text": "LAD and LCX branch from LCA."}, {"id": "d", "text": "LAD supplies anterior wall and most septum."}, {"id": "e", "text": "LCX supplies right ventricle primarily in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Left coronary artery branches into LAD and LCX; LAD supplies anterior LV and 2/3 septum, LCX supplies lateral LV wall.', 'Heart Structure and Circulation - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to RCA territory. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to RCA territory. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "RCA supplies only left atrium in this note."}, {"id": "b", "text": "PDA branch from RCA is listed."}, {"id": "c", "text": "Posterior wall supply is associated with RCA here."}, {"id": "d", "text": "RCA supplies right ventricle."}, {"id": "e", "text": "RCA has no major branches in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: RCA supplies right ventricle and posterior wall and branches into PDA in this note.', 'Heart Structure and Circulation - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving S1 sound, which options are appropriate? (Select all that apply)', 'For assessment involving S1 sound, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "S1 marks beginning of systole."}, {"id": "b", "text": "S1 is semilunar valve closure in this note."}, {"id": "c", "text": "S1 corresponds to AV valve closure."}, {"id": "d", "text": "S1 marks end of systole in this note."}, {"id": "e", "text": "S1 is a normal sound in this context."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: S1 (lub) is closure of mitral and tricuspid valves at start of systole.', 'Heart Structure and Circulation - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and S2 sound. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and S2 sound. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "S2 is semilunar valve closure."}, {"id": "b", "text": "S2 marks end of systole."}, {"id": "c", "text": "S2 is AV valve closure in this note."}, {"id": "d", "text": "Aortic and pulmonic closure create S2."}, {"id": "e", "text": "S2 indicates ventricular filling start only in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: S2 (dub) is closure of aortic and pulmonic valves, marking end of systole.', 'Heart Structure and Circulation - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support S3 significance? (Select all that apply)', 'During reassessment, which observations support S3 significance? (Select all that apply)', '[{"id": "a", "text": "S3 is normal adult athletic finding in this note."}, {"id": "b", "text": "S3 indicates valvular stenosis only in this note."}, {"id": "c", "text": "S3 associates with heart failure."}, {"id": "d", "text": "S3 is tied to rapid ventricular filling."}, {"id": "e", "text": "S3 in adults is abnormal in this note."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: S3 is linked to rapid ventricular filling and is abnormal in adults, associated with heart failure.', 'Heart Structure and Circulation - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with S4 significance in this note? (Select all that apply)', 'Which cues are consistent with S4 significance in this note? (Select all that apply)', '[{"id": "a", "text": "Hypertension is linked with S4 in note."}, {"id": "b", "text": "S4 comes from atrial kick into stiff ventricle."}, {"id": "c", "text": "S4 indicates acute pulmonary embolism in this note."}, {"id": "d", "text": "HCM is linked with S4 in note."}, {"id": "e", "text": "S4 is caused by AV valve closure in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: S4 reflects atrial kick against a stiff ventricle and is associated with hypertension and hypertrophic cardiomyopathy.', 'Heart Structure and Circulation - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for concepts related to Murmur meaning. Which findings/statements are correct? (Select all that apply)', 'A patient is evaluated for concepts related to Murmur meaning. Which findings/statements are correct? (Select all that apply)', '[{"id": "a", "text": "Murmurs are always benign in this note."}, {"id": "b", "text": "Regurgitation can cause murmur."}, {"id": "c", "text": "Murmur means turbulent flow."}, {"id": "d", "text": "Stenosis can cause murmur."}, {"id": "e", "text": "Murmurs indicate normal laminar flow in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Murmurs represent turbulent blood flow and may indicate valve stenosis or regurgitation.', 'Heart Structure and Circulation - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For assessment involving NCLEX sound mnemonics, which options are appropriate? (Select all that apply)', 'For assessment involving NCLEX sound mnemonics, which options are appropriate? (Select all that apply)', '[{"id": "a", "text": "S4 is linked to normal youthful physiology in this note."}, {"id": "b", "text": "S3 mnemonic is Tennessee in this note."}, {"id": "c", "text": "S4 mnemonic is Tennessee in note."}, {"id": "d", "text": "S3 mnemonic is Kentucky in note."}, {"id": "e", "text": "Mnemonic pairing reflects HF vs stiff ventricle context."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: NCLEX note links S3 to â€śKen-tuc-kyâ€ť and heart failure, and S4 to â€śTen-nes-seeâ€ť and stiff ventricles/HTN.', 'Heart Structure and Circulation - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse teaches cardiac flow and Integrated circulation reasoning. Which points should be included? (Select all that apply)', 'The nurse teaches cardiac flow and Integrated circulation reasoning. Which points should be included? (Select all that apply)', '[{"id": "a", "text": "Gas exchange occurs in left ventricle in this note."}, {"id": "b", "text": "Lungs are gas-exchange site in sequence."}, {"id": "c", "text": "Pulmonary venous return is oxygenated."}, {"id": "d", "text": "LA receives oxygenated blood before LV systemic ejection."}, {"id": "e", "text": "Aorta returns deoxygenated blood to RA in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Gas exchange occurs in lungs between pulmonary artery output and pulmonary vein return, enabling oxygenated LA inflow before systemic ejection.', 'Heart Structure and Circulation - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Right heart role? (Select all that apply)', 'During reassessment, which observations support Right heart role? (Select all that apply)', '[{"id": "a", "text": "RV pumps to lungs."}, {"id": "b", "text": "Right atrium receives blood from pulmonary veins in this note."}, {"id": "c", "text": "Pulmonary circuit begins from right ventricle."}, {"id": "d", "text": "RA receives deoxygenated blood from SVC/IVC."}, {"id": "e", "text": "Right heart pumps oxygenated blood to aorta in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Right heart receives deoxygenated venous blood and pumps it to lungs via pulmonary circulation.', 'Heart Structure and Circulation - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Left heart role in this note? (Select all that apply)', 'Which cues are consistent with Left heart role in this note? (Select all that apply)', '[{"id": "a", "text": "Left atrium receives blood from SVC in this note."}, {"id": "b", "text": "Left ventricle empties into pulmonary artery in this note."}, {"id": "c", "text": "LV pumps blood to body via aorta."}, {"id": "d", "text": "LA receives oxygenated blood from lungs."}, {"id": "e", "text": "Systemic circulation is driven by left ventricle."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Left heart receives oxygenated blood from pulmonary veins and pumps it systemically via aorta.', 'Heart Structure and Circulation - NCLEX', true, 100, 1, true);
